# Unit Tests for `flatten_dict`

```python
import pytest
from mymodule import flatten_dict  # adjust the import to your module


class TestFlattenDictHappyPath:
    """Tests for typical, expected use cases."""

    def test_flat_dict_unchanged(self):
        """A dict with no nesting should be returned as-is."""
        d = {"a": 1, "b": 2, "c": 3}
        assert flatten_dict(d) == {"a": 1, "b": 2, "c": 3}

    def test_single_level_nesting(self):
        d = {"a": {"b": 1}}
        assert flatten_dict(d) == {"a.b": 1}

    def test_multi_level_nesting(self):
        d = {"a": {"b": {"c": {"d": 42}}}}
        assert flatten_dict(d) == {"a.b.c.d": 42}

    def test_mixed_nested_and_flat(self):
        d = {"a": 1, "b": {"c": 2, "d": {"e": 3}}, "f": 4}
        assert flatten_dict(d) == {
            "a": 1,
            "b.c": 2,
            "b.d.e": 3,
            "f": 4,
        }

    def test_multiple_keys_same_level_nested(self):
        d = {"x": {"a": 1, "b": 2}, "y": {"c": 3, "d": 4}}
        assert flatten_dict(d) == {
            "x.a": 1,
            "x.b": 2,
            "y.c": 3,
            "y.d": 4,
        }


class TestFlattenDictCustomSeparator:
    """Tests around the `sep` parameter."""

    def test_custom_separator_underscore(self):
        d = {"a": {"b": {"c": 1}}}
        assert flatten_dict(d, sep="_") == {"a_b_c": 1}

    def test_custom_separator_slash(self):
        d = {"a": {"b": 1}, "c": 2}
        assert flatten_dict(d, sep="/") == {"a/b": 1, "c": 2}

    def test_empty_separator(self):
        d = {"a": {"b": 1}}
        assert flatten_dict(d, sep="") == {"ab": 1}

    def test_multichar_separator(self):
        d = {"a": {"b": 1}}
        assert flatten_dict(d, sep="->") == {"a->b": 1}


class TestFlattenDictParentKey:
    """Tests around the `parent_key` parameter."""

    def test_parent_key_prepended(self):
        d = {"a": 1, "b": 2}
        assert flatten_dict(d, parent_key="root") == {"root.a": 1, "root.b": 2}

    def test_parent_key_with_nesting(self):
        d = {"a": {"b": 1}}
        assert flatten_dict(d, parent_key="root") == {"root.a.b": 1}

    def test_empty_parent_key_default_behavior(self):
        d = {"a": 1}
        assert flatten_dict(d, parent_key="") == {"a": 1}


class TestFlattenDictEdgeCases:
    """Edge cases - empty dicts, special values, etc."""

    def test_empty_dict(self):
        assert flatten_dict({}) == {}

    def test_empty_dict_with_parent_key(self):
        assert flatten_dict({}, parent_key="root") == {}

    def test_empty_nested_dict_disappears(self):
        """An empty nested dict has no leaves, so it should not appear in the output."""
        d = {"a": 1, "b": {}}
        assert flatten_dict(d) == {"a": 1}

    def test_only_empty_nested_dicts(self):
        d = {"a": {}, "b": {}}
        assert flatten_dict(d) == {}

    def test_deeply_nested_empty_dict(self):
        d = {"a": {"b": {"c": {}}}}
        assert flatten_dict(d) == {}

    def test_none_value_preserved(self):
        d = {"a": None, "b": {"c": None}}
        assert flatten_dict(d) == {"a": None, "b.c": None}

    def test_list_values_treated_as_leaves(self):
        d = {"a": [1, 2, 3], "b": {"c": [4, 5]}}
        assert flatten_dict(d) == {"a": [1, 2, 3], "b.c": [4, 5]}

    def test_tuple_values_treated_as_leaves(self):
        d = {"a": (1, 2)}
        assert flatten_dict(d) == {"a": (1, 2)}

    def test_boolean_values(self):
        d = {"a": True, "b": {"c": False}}
        assert flatten_dict(d) == {"a": True, "b.c": False}

    def test_zero_and_empty_string_values(self):
        d = {"a": 0, "b": "", "c": {"d": 0.0}}
        assert flatten_dict(d) == {"a": 0, "b": "", "c.d": 0.0}

    def test_non_string_keys(self):
        d = {1: "a", 2: {3: "b"}}
        assert flatten_dict(d) == {"1": "a", "2.3": "b"}

    def test_separator_appears_in_keys(self):
        """Keys containing the separator are not escaped — make sure behavior is documented."""
        d = {"a.b": {"c": 1}}
        # Result will have ambiguous key 'a.b.c'
        assert flatten_dict(d) == {"a.b.c": 1}

    def test_does_not_mutate_input(self):
        d = {"a": {"b": 1}}
        original = {"a": {"b": 1}}
        flatten_dict(d)
        assert d == original

    def test_returns_new_dict_instance(self):
        d = {"a": 1}
        result = flatten_dict(d)
        assert result
